{"meta": null, "content": [{"type": "text", "text": "{"content":"1: #include \"source/extensions/filters/http/header_to_metadata/header_to_metadata_filter.h\"\n2: \n3: #include \"envoy/extensions/filters/http/header_to_metadata/v3/header_to_metadata.pb.h\"\n4: \n5: #include \"source/common/common/base64.h\"\n6: #include \"source/common/common/regex.h\"\n7: #include \"source/common/config/well_known_names.h\"\n8: #include \"source/common/http/header_utility.h\"\n9: #include \"source/common/http/utility.h\"\n10: #include \"source/common/protobuf/protobuf.h\"\n11: #include \"source/extensions/filters/http/well_known_names.h\"\n12: \n13: #include \"absl/strings/numbers.h\"\n14: #include \"absl/strings/string_view.h\"\n15: \n16: namespace Envoy {\n17: namespace Extensions {\n18: namespace HttpFilters {\n19: namespace HeaderToMetadataFilter {\n20: \n21: // Extract the value of the header.\n22: absl::optional\u003cstd::string\u003e HeaderValueSelector::extract(Http::HeaderMap\u0026 map) const {\n23:   const auto header_value = Http::HeaderUtility::getAllOfHeaderAsString(map, header_);\n24:   if (!header_value.result().has_value()) {\n25:     return absl::nullopt;\n26:   }\n27:   // Catch the value in the header before removing.\n28:   absl::optional\u003cstd::string\u003e value = std::string(header_value.result().value());\n29:   if (remove_) {\n30:     map.remove(header_);\n31:   }\n32:   return value;\n33: }\n34: \n35: // Extract the value of the key from the cookie header.\n36: absl::optional\u003cstd::string\u003e CookieValueSelector::extract(Http::HeaderMap\u0026 map) const {\n37:   std::string value = Envoy::Http::Utility::parseCookieValue(map, cookie_);\n38:   if (!value.empty()) {\n39:     return {std::move(value)};\n40:   }\n41:   return absl::nullopt;\n42: }\n43: \n44: Rule::Rule(const ProtoRule\u0026 rule, Regex::Engine\u0026 regex_engine) : rule_(rule) {\n45:   // Ensure only one of header and cookie is specified.\n46:   // TODO(radha13): remove this once we ar