21: // Extract the value of the header.
22: absl::optional<std::string> HeaderValueSelector::extract(Http::HeaderMap& map) const {
23:   const auto header_value = Http::HeaderUtility::getAllOfHeaderAsString(map, header_);
24:   if (!header_value.result().has_value()) {
25:     return absl::nullopt;
26:   }
27:   // Catch the value in the header before removing.
28:   absl::optional<std::string> value = std::string(header_value.result().value());
29:   if (remove_) {
30:     map.remove(header_);
31:   }
32:   return value;
33: }
