231: void HeaderToMetadataFilter::writeHeaderToMetadata(Http::HeaderMap& headers,
232:                                                    const HeaderToMetadataRules& rules,
233:                                                    Http::StreamFilterCallbacks& callbacks) {
234:   StructMap structs_by_namespace;
235: 
236:   for (const auto& rule : rules) {
237:     const auto& proto_rule = rule.rule();
238:     absl::optional<std::string> value = rule.selector_->extract(headers);
239: 
240:     if (value && proto_rule.has_on_header_present()) {
241:       applyKeyValue(std::move(value).value_or(""), rule, proto_rule.on_header_present(),
242:                     structs_by_namespace);
243:     } else if (!value && proto_rule.has_on_header_missing()) {
244:       applyKeyValue(std::move(value).value_or(""), rule, proto_rule.on_header_missing(),
245:                     structs_by_namespace);
246:     }
247:   }
248:   // Any matching rules?
249:   if (!structs_by_namespace.empty()) {
250:     for (auto const& entry : structs_by_namespace) {
251:       callbacks.streamInfo().setDynamicMetadata(entry.first, entry.second);
252:     }
253:   }
254: }
