#pragma once

#include <string>
#include <vector>

#include "envoy/http/filter.h"
#include "envoy/server/filter_config.h"

#include "source/common/common/logger.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Represents a single header name/value pair to inject.
 */
struct HeaderEntry {
  std::string name;
  std::string value;
};

/**
 * Immutable filter configuration holding the headers to inject into
 * requests and responses.
 */
class FilterConfig {
public:
  FilterConfig(std::vector<HeaderEntry> request_headers_to_add,
               std::vector<HeaderEntry> response_headers_to_add)
      : request_headers_to_add_(std::move(request_headers_to_add)),
        response_headers_to_add_(std::move(response_headers_to_add)) {}

  const std::vector<HeaderEntry>& requestHeadersToAdd() const {
    return request_headers_to_add_;
  }
  const std::vector<HeaderEntry>& responseHeadersToAdd() const {
    return response_headers_to_add_;
  }

private:
  const std::vector<HeaderEntry> request_headers_to_add_;
  const std::vector<HeaderEntry> response_headers_to_add_;
};

using FilterConfigSharedPtr = std::shared_ptr<FilterConfig>;

/**
 * HTTP filter that injects configurable headers into requests and/or responses.
 *
 * Implements both StreamDecoderFilter (request path) and StreamEncoderFilter
 * (response path) via the combined StreamFilter interface.
 */
class CustomHeaderInjectionFilter : public Http::StreamFilter,
                                    public Logger::Loggable<Logger::Id::filter> {
public:
  explicit CustomHeaderInjectionFilter(FilterConfigSharedPtr config);
  ~CustomHeaderInjectionFilter() override = default;

  // Http::StreamFilterBase
  void onDestroy() override {}

  // Http::StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers,
                                          bool end_stream) override;
  Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;

  // Http::StreamEncoderFilter
  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
    return Http::Filter1xxHeadersStatus::Continue;
  }
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers,
                                          bool end_stream) override;
  Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
    return Http::FilterMetadataStatus::Continue;
  }
  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;

private:
  const FilterConfigSharedPtr config_;
  Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
  Http::StreamEncoderFilterCallbacks* encoder_callbacks_{};
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "envoy/http/header_map.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(FilterConfigSharedPtr config)
    : config_(std::move(config)) {}

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
  for (const auto& entry : config_->requestHeadersToAdd()) {
    ENVOY_LOG(debug, "custom_header_injection: adding request header '{}': '{}'", entry.name,
              entry.value);
    headers.addCopy(Http::LowerCaseString(entry.name), entry.value);
  }
  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::setDecoderFilterCallbacks(
    Http::StreamDecoderFilterCallbacks& callbacks) {
  decoder_callbacks_ = &callbacks;
}

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
  for (const auto& entry : config_->responseHeadersToAdd()) {
    ENVOY_LOG(debug, "custom_header_injection: adding response header '{}': '{}'", entry.name,
              entry.value);
    headers.addCopy(Http::LowerCaseString(entry.name), entry.value);
  }
  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::setEncoderFilterCallbacks(
    Http::StreamEncoderFilterCallbacks& callbacks) {
  encoder_callbacks_ = &callbacks;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#pragma once

#include "source/extensions/filters/http/common/factory_base.h"
#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "google/protobuf/struct.pb.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Config registration for the custom_header_injection filter.
 *
 * The filter is configured via a google.protobuf.Struct with two optional
 * sub-structs:
 *   - "request_headers_to_add":  { "<header-name>": "<header-value>", ... }
 *   - "response_headers_to_add": { "<header-name>": "<header-value>", ... }
 *
 * @see NamedHttpFilterConfigFactory.
 */
class CustomHeaderInjectionConfig
    : public Common::FactoryBase<ProtobufWkt::Struct> {
public:
  CustomHeaderInjectionConfig()
      : FactoryBase("envoy.filters.http.custom_header_injection") {}

private:
  Http::FilterFactoryCb createFilterFactoryFromProtoTyped(
      const ProtobufWkt::Struct& proto_config, const std::string& stats_prefix,
      Server::Configuration::FactoryContext& context) override;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/config.h"

#include "envoy/registry/registry.h"

#include "source/extensions/filters/http/custom_header_injection/filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

namespace {

// Parse a sub-struct field into a vector of HeaderEntry.
std::vector<HeaderEntry>
parseHeaderEntries(const ProtobufWkt::Struct& proto_config, const std::string& field_name) {
  std::vector<HeaderEntry> entries;
  const auto& fields = proto_config.fields();
  const auto it = fields.find(field_name);
  if (it == fields.end()) {
    return entries;
  }
  if (it->second.kind_case() != ProtobufWkt::Value::kStructValue) {
    return entries;
  }
  for (const auto& kv : it->second.struct_value().fields()) {
    if (kv.second.kind_case() == ProtobufWkt::Value::kStringValue) {
      entries.push_back({kv.first, kv.second.string_value()});
    }
  }
  return entries;
}

} // namespace

Http::FilterFactoryCb CustomHeaderInjectionConfig::createFilterFactoryFromProtoTyped(
    const ProtobufWkt::Struct& proto_config, const std::string&,
    Server::Configuration::FactoryContext&) {
  auto request_headers = parseHeaderEntries(proto_config, "request_headers_to_add");
  auto response_headers = parseHeaderEntries(proto_config, "response_headers_to_add");

  auto filter_config = std::make_shared<FilterConfig>(std::move(request_headers),
                                                      std::move(response_headers));

  return [filter_config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamFilter(
        Http::StreamFilterSharedPtr{new CustomHeaderInjectionFilter(filter_config)});
  };
}

/**
 * Static registration for the custom_header_injection filter. @see RegisterFactory.
 */
REGISTER_FACTORY(CustomHeaderInjectionConfig, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

