    13
    14  // Parse a sub-struct field into a vector of HeaderEntry.
    15  std::vector<HeaderEntry>
    16  parseHeaderEntries(const ProtobufWkt::Struct& proto_config, const std::string& field_name) {
    17    std::vector<HeaderEntry> entries;
    18    const auto& fields = proto_config.fields();
    19    const auto it = fields.find(field_name);
    20    if (it == fields.end()) {
    21      return entries;
    22    }
    23    if (it->second.kind_case() != ProtobufWkt::Value::kStructValue) {
    24      return entries;
    25    }
    26    for (const auto& kv : it->second.struct_value().fields()) {
    27      if (kv.second.kind_case() == ProtobufWkt::Value::kStringValue) {
    28        entries.push_back({kv.first, kv.second.string_value()});
    29      }
    30    }
    31    return entries;
    32  }
    33
    34  } // namespace
    35
    36  Http::FilterFactoryCb CustomHeaderInjectionConfig::createFilterFactoryFromProtoTyped(
    37      const ProtobufWkt::Struct& proto_config, const std::string&,
    38      Server::Configuration::FactoryContext&) {
    39    auto request_headers = parseHeaderEntries(proto_config, "request_headers_to_add");
    40    auto response_headers = parseHeaderEntries(proto_config, "response_headers_to_add");
    41
    42    auto filter_config = std::make_shared<FilterConfig>(std::move(request_headers),
    43                                                        std::move(response_headers));
    44
    45    return [filter_config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    46      callbacks.addStreamFilter(
    47          Http::StreamFilterSharedPtr{new CustomHeaderInjectionFilter(filter_config)});
    48    };
    49  }
    50
    51  /**
    52   * Static registration for the custom_header_injection filter. @see RegisterFactory.
    53   */
    54  REGISTER_FACTORY(CustomHeaderInjectionConfig, Server::Configuration::NamedHttpFilterConfigFactory);
